        # op-REUSE: mixer.out_proj  (Linear 4096 -> 2688, bias=False)
        self.w_mixer_out_proj_weight = ttnn.from_torch(sd['mixer.out_proj.weight'].T.contiguous(), dtype=ttnn.bfloat16, layout=ttnn.TILE_LAYOUT, device=device)

